using UnityEngine;

public class Operators : MonoBehaviour
{
    void Start()
    {
        // Arithmetic
        int health = 100;
        int damage = 25;
        int newHealth = health - damage;
        int doubleDamage = damage * 2;
        int quotient = 10 / 3;  // Integer division = 3
        int remainder = 10 % 3; // Modulus = 1

        Debug.Log("New health: " + newHealth);
        Debug.Log("Double damage: " + doubleDamage);
        Debug.Log("Quotient: " + quotient);
        Debug.Log("Remainder: " + remainder);

        // Comparison
        bool isDead = health <= 0;
        bool isFullHealth = health == 100;
        bool hasEnoughGold = 50 >= 30;
        bool isDifferent = 10 != 5;

        Debug.Log("Is dead? " + isDead);
        Debug.Log("Full health? " + isFullHealth);
        Debug.Log("Enough gold? " + hasEnoughGold);
        Debug.Log("Is different? " + isDifferent);

        // Logical
        bool hasKey = true;
        bool hasSword = false;
        bool canEnterBossRoom = hasKey && hasSword;
        bool canHeal = hasKey || hasSword;
        bool isNotReady = !hasSword;

        Debug.Log("Can enter boss room? " + canEnterBossRoom);
        Debug.Log("Can heal? " + canHeal);
        Debug.Log("Is not ready? " + isNotReady);

        // Compound assignment
        int gold = 50;
        gold += 20;  // gold = gold + 20 = 70
        gold *= 2;   // gold = gold * 2 = 140

        Debug.Log("Gold after pickup: " + gold);
    }
}

phase2.brokenCode:
using UnityEngine;

public class OperatorError : MonoBehaviour
{
    void Start()
    {
        // Mistake: using = instead of == in a condition
        int health = 50;

        if (health = 100)  // ERROR: Cannot assign int to bool
        {
            Debug.Log("Full health!");
        }
    }
}

phase2.explanation:
`=` is assignment, `==` is comparison.

**The fix:**
```csharp
if (health == 100)  // Compare, don't assign
{
    Debug.Log("Full health!");
}
```

**Sharp-chan says:**
"This is a classic mistake. `=` sets a value. `==` checks if two values are equal. They are not interchangeable."
